import { useState } from "react";
import {
  Grid,
  Button,
  Typography,
  Paper,
  TextField,
  Snackbar,
} from "@material-ui/core";
import Alert from "@material-ui/lab/Alert";
import { makeStyles } from "@material-ui/core/styles";
import axios from "axios";
import Grow from "@material-ui/core/Grow";
import React, { useRef } from "react";

const API_BASE = process.env.REACT_APP_API_URL;

const useStyles = makeStyles((theme) => ({
  root: {
    height: "100vh",
    backgroundColor: theme.palette.grey[100],
  },
  paper: {
    padding: theme.spacing(4),
    margin: "auto",
    maxWidth: 400,
    marginTop: theme.spacing(10),
  },
  input: {
    marginBottom: theme.spacing(2),
  },
}));

export default function Login() {
  const classes = useStyles();
  const [loginDetails, setLoginDetails] = useState({
    email: "",
    password: "",
  });

  const [popup, setPopup] = useState({
    open: false,
    severity: "info",
    message: "",
  });

  const handleInput = (key, value) => {
    setLoginDetails((prev) => ({
      ...prev,
      [key]: value,
    }));
  };

  const handleLogin = async (e) => {
    e.preventDefault();

    try {
      const res = await axios.post(`${API_BASE}/auth/login`, loginDetails, {
        headers: {
          "Content-Type": "application/json",
        },
      });

      if (res.status === 200) {
        localStorage.setItem("token", res.data.token);
        setPopup({
          open: true,
          severity: "success",
          message: "Login successful!",
        });
      }
    } catch (err) {
      const message =
        err.response?.data?.error || "Login failed. Check credentials.";
      setPopup({
        open: true,
        severity: "error",
        message,
      });
    }
  };

  return (
    <Grid
      container
      className={classes.root}
      justifyContent="center"
      alignItems="center"
    >
      <Paper className={classes.paper} elevation={3} component={Grow} in>
        <form onSubmit={handleLogin}>
          <Typography variant="h5" gutterBottom>
            Login
          </Typography>
          <TextField
            label="Email"
            type="email"
            variant="outlined"
            fullWidth
            className={classes.input}
            value={loginDetails.email}
            onChange={(e) => handleInput("email", e.target.value)}
            required
          />
          <TextField
            label="Password"
            type="password"
            variant="outlined"
            fullWidth
            className={classes.input}
            value={loginDetails.password}
            onChange={(e) => handleInput("password", e.target.value)}
            required
          />
          <Button variant="contained" color="primary" type="submit" fullWidth>
            Login
          </Button>
        </form>
      </Paper>

      <Snackbar
        open={popup.open}
        autoHideDuration={4000}
        onClose={() => setPopup({ ...popup, open: false })}
      >
        <Alert severity={popup.severity}>{popup.message}</Alert>
      </Snackbar>
    </Grid>
  );
}
